/// Standing Wave Pinning for Distributed Inference Mesh
/// ====================================================
///
/// Transforms the distributed inference worker mesh into a pin cushion:
/// every hidden state is routed through standing wave dimensions only.
///
/// Key: Extract which embedding dimensions matter (k << d) from attention patterns,
/// pin all inter-worker routing to those k dimensions, achieve 5-17x speedup.
use std::collections::HashMap;

use crate::attention_closure_lift::{
    attention_closure_optimization_policy, AttentionClosureOptimizationPolicy,
    AttentionClosureState,
};

/// Attention pattern signature extracted from a transformer head
#[derive(Debug, Clone)]
pub struct AttentionWaveSignature {
    pub layer_idx: usize,
    pub head_idx: usize,
    pub hidden_dim: usize,
    pub query_amplitudes: Vec<f32>,   // Q amplitude per dimension
    pub key_amplitudes: Vec<f32>,     // K amplitude per dimension
    pub value_amplitudes: Vec<f32>,   // V amplitude per dimension
    pub qk_phase_alignment: Vec<f32>, // How well Q-K align in phase per dim
    pub output_amplitudes: Vec<f32>,  // Output amplitude per dimension
}

/// Standing wave dimensions: k << d where information concentrates
#[derive(Debug, Clone)]
pub struct StandingWaveDimensions {
    pub layer_idx: usize,
    pub hidden_dim: usize,
    pub standing_dims: Vec<usize>, // Indices where standing waves exist
    pub coverage: f32,             // k / d: fraction of dimensions
    pub speedup_factor: f32,       // Estimated: d / k
}

impl StandingWaveDimensions {
    /// Extract standing wave dimensions from attention signature.
    /// Standing: Q, K, V all > 0.5 amplitude AND phase-aligned > 0.5.
    ///
    /// Note: this absolute-threshold form collapses to ~0 standing dims on
    /// real single-token forward passes because the per-dim raw amplitudes
    /// rarely exceed the (signature-normalized) 0.5 floor. Prefer
    /// `extract_top_k` for production use against real models — it picks the
    /// top `target_coverage * d` dims by joint score, so coverage is bounded
    /// by construction. Kept here for backward compatibility with tests
    /// that hand-build saturated signatures.
    pub fn extract(sig: &AttentionWaveSignature) -> Self {
        let mut standing_dims = Vec::new();

        for i in 0..sig.hidden_dim {
            let is_standing = sig.query_amplitudes[i] > 0.5
                && sig.key_amplitudes[i] > 0.5
                && sig.value_amplitudes[i] > 0.5
                && sig.qk_phase_alignment[i] > 0.5;

            if is_standing {
                standing_dims.push(i);
            }
        }

        let k = standing_dims.len() as f32;
        let d = sig.hidden_dim as f32;
        let coverage = k / d;
        let speedup_factor = d / k.max(1.0);

        StandingWaveDimensions {
            layer_idx: sig.layer_idx,
            hidden_dim: sig.hidden_dim,
            standing_dims,
            coverage,
            speedup_factor,
        }
    }

    /// Pick the top `target_coverage * hidden_dim` dimensions ranked by joint
    /// standing-wave score: `min(q, k, v) * phase_alignment`. The min-of-Q/K/V
    /// term enforces "all three components present" without collapsing on a
    /// single weak component; the phase-alignment factor downweights dims
    /// where Q and K disagree on which token they attend to.
    ///
    /// This produces a deterministic coverage by construction — useful for
    /// running against real models where the absolute thresholds in
    /// `extract` filter everything out.
    pub fn extract_top_k(sig: &AttentionWaveSignature, target_coverage: f32) -> Self {
        let d = sig.hidden_dim;
        let k = ((d as f32) * target_coverage).round().clamp(1.0, d as f32) as usize;

        let mut scored: Vec<(usize, f32)> = (0..d)
            .map(|i| {
                let qkv_min = sig.query_amplitudes[i]
                    .min(sig.key_amplitudes[i])
                    .min(sig.value_amplitudes[i]);
                let score = qkv_min * sig.qk_phase_alignment[i];
                (i, score)
            })
            .collect();

        // Highest score first
        scored.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));

        let mut standing_dims: Vec<usize> = scored.into_iter().take(k).map(|(i, _)| i).collect();
        // Keep dims sorted ascending so compress/decompress index access is monotonic
        standing_dims.sort_unstable();

        let coverage = (k as f32) / (d as f32);
        let speedup_factor = (d as f32) / (k as f32).max(1.0);

        StandingWaveDimensions {
            layer_idx: sig.layer_idx,
            hidden_dim: d,
            standing_dims,
            coverage,
            speedup_factor,
        }
    }
}

/// Mesh routing with standing wave pinning
pub struct StandingWaveMesh {
    pub layers: HashMap<usize, StandingWaveDimensions>,
    pub global_coverage: f32,
    pub global_speedup: f32,
}

impl StandingWaveMesh {
    /// Build pinned mesh from layer signatures
    pub fn build(signatures: Vec<AttentionWaveSignature>) -> Self {
        let mut layers = HashMap::new();
        let mut total_coverage = 0.0;
        let mut total_speedup = 0.0;

        for sig in signatures {
            let sw = StandingWaveDimensions::extract(&sig);
            total_coverage += sw.coverage;
            total_speedup += sw.speedup_factor;
            layers.insert(sig.layer_idx, sw);
        }

        let layer_count = layers.len() as f32;
        let global_coverage = if layer_count > 0.0 {
            total_coverage / layer_count
        } else {
            1.0
        };
        let global_speedup = if layer_count > 0.0 {
            total_speedup / layer_count
        } else {
            1.0
        };

        StandingWaveMesh {
            layers,
            global_coverage,
            global_speedup,
        }
    }

    /// Get standing wave dims for a layer
    pub fn get_standing_dims(&self, layer_idx: usize) -> Option<&Vec<usize>> {
        self.layers.get(&layer_idx).map(|sw| &sw.standing_dims)
    }
}

/// Compress hidden state to standing dimensions
pub fn compress_to_standing(hidden_state: &[f32], standing_dims: &[usize]) -> Vec<f32> {
    let mut compressed = vec![0.0; standing_dims.len()];
    for (i, &dim) in standing_dims.iter().enumerate() {
        if dim < hidden_state.len() {
            compressed[i] = hidden_state[dim];
        }
    }
    compressed
}

#[derive(Debug, Clone, PartialEq)]
pub struct ClosureAwareStandingRoute {
    pub payload: Vec<f32>,
    pub compressed: bool,
    pub original_size_bytes: usize,
    pub routed_size_bytes: usize,
    pub theorem_lineage: &'static [&'static str],
    pub policy: AttentionClosureOptimizationPolicy,
}

/// Route through standing dimensions only after attention closure is separated.
///
/// An aliased 8-head trace can make the standing dims look stable before the
/// observer has enough resolution to distinguish the heads. In that case this
/// helper preserves the full hidden state and reports the closure policy so
/// callers can lift resolution before paying compression/decompression work.
pub fn compress_to_standing_with_attention_closure(
    hidden_state: &[f32],
    standing_dims: &[usize],
    attention_closure: AttentionClosureState,
    residue_threshold: usize,
) -> ClosureAwareStandingRoute {
    let policy = attention_closure_optimization_policy(attention_closure, residue_threshold, 1);
    let payload = if policy.allow_standing_wave_compression {
        compress_to_standing(hidden_state, standing_dims)
    } else {
        hidden_state.to_vec()
    };
    let original_size_bytes = hidden_state
        .len()
        .saturating_mul(std::mem::size_of::<f32>());
    let routed_size_bytes = payload.len().saturating_mul(std::mem::size_of::<f32>());

    ClosureAwareStandingRoute {
        payload,
        compressed: policy.allow_standing_wave_compression,
        original_size_bytes,
        routed_size_bytes,
        theorem_lineage: policy.theorem_lineage,
        policy,
    }
}

/// Decompress from standing dimensions back to full space, zero-filling
/// non-standing dims. This is the original/strict reconstruction — it breaks
/// transformer residual sums (see standing-wave-parity sweep). Use
/// `decompress_from_standing_with_fill` to test non-zero fillers.
pub fn decompress_from_standing(
    compressed: &[f32],
    standing_dims: &[usize],
    full_dim: usize,
) -> Vec<f32> {
    let mut full = vec![0.0; full_dim];
    for (i, &dim) in standing_dims.iter().enumerate() {
        if i < compressed.len() && dim < full_dim {
            full[dim] = compressed[i];
        }
    }
    full
}

/// Build a `k × d` orthonormal projection matrix via Gram-Schmidt over random
/// Gaussian rows. Returned as a flat row-major `Vec<f32>` of length `k * d`.
/// Same `seed` returns the same matrix bit-for-bit, so sender and receiver
/// produce identical bases without any wire transfer.
///
/// O · O^T = I_k (orthonormal rows). Use `project_orthogonal` to compress
/// `x ∈ ℝ^d` to `x' = O · x ∈ ℝ^k`, and `lift_orthogonal` to reconstruct
/// `x_recon = O^T · x' ∈ ℝ^d` (the rank-k projection of x onto row(O)).
///
/// Cost: O(k * d^2) one-time at construction. For Qwen2.5-0.5B (k=269, d=896)
/// that's ~216M flops — sub-second on CPU. For Gemma4-31B (k=1612, d=5376)
/// it's ~46G flops — minutes. In production you'd cache the basis as a `.bin`
/// alongside the knot.
pub fn random_orthogonal_basis(k: usize, d: usize, seed: u64) -> Vec<f32> {
    assert!(k <= d, "orthogonal basis requires k <= d");
    let mut rng = fastrand::Rng::with_seed(seed);
    let mut basis = vec![0.0f32; k * d];

    // Box-Muller standard normal
    let sample_normal = |rng: &mut fastrand::Rng| -> f32 {
        let u1 = (rng.f32().max(1e-9)).min(1.0 - 1e-9);
        let u2 = rng.f32();
        let r = (-2.0_f32 * u1.ln()).sqrt();
        let theta = 2.0_f32 * std::f32::consts::PI * u2;
        r * theta.cos()
    };

    // Fill rows with N(0,1) noise
    for v in basis.iter_mut() {
        *v = sample_normal(&mut rng);
    }

    // Modified Gram-Schmidt: orthonormalize row-by-row.
    for i in 0..k {
        // Subtract projections onto rows 0..i
        for j in 0..i {
            let mut dot = 0.0f32;
            for c in 0..d {
                dot += basis[i * d + c] * basis[j * d + c];
            }
            for c in 0..d {
                basis[i * d + c] -= dot * basis[j * d + c];
            }
        }
        // Normalize row i
        let mut norm_sq = 0.0f32;
        for c in 0..d {
            norm_sq += basis[i * d + c] * basis[i * d + c];
        }
        let norm = norm_sq.sqrt().max(1e-12);
        let inv = 1.0 / norm;
        for c in 0..d {
            basis[i * d + c] *= inv;
        }
    }
    basis
}

/// Fit a `k × d` PCA basis on `samples` via power iteration with deflation.
/// Returns `(mean: [d], basis: [k * d])` row-major. The basis rows are the
/// top-k eigenvectors of the empirical covariance `C = (1/n) X^T X` where
/// `X` is the centered sample matrix.
///
/// `num_iter` controls per-component power iteration steps. 20-30 is
/// usually enough for well-separated eigenvalues; near-degenerate spectra
/// need more (or a switch to subspace iteration). For our use case
/// (transformer activations, k ≪ d) 30 iterations is comfortable.
///
/// Cost: O(k · num_iter · n · d). For k=448 d=896 n=200 num_iter=30 this
/// is ~2.4 GFLOPS, sub-10 seconds on CPU.
///
/// PCA gives the **L2-optimal unsupervised rank-k linear reconstruction**
/// of `samples`. It is NOT necessarily optimal for downstream task loss
/// (e.g. logit preservation) — a Fisher-weighted or task-aware projection
/// could in principle beat PCA on argmax preservation while doing worse
/// on residual MSE.
pub fn fit_pca(samples: &[Vec<f32>], k: usize, num_iter: usize, seed: u64) -> (Vec<f32>, Vec<f32>) {
    assert!(!samples.is_empty(), "fit_pca: empty samples");
    let n = samples.len();
    let d = samples[0].len();
    assert!(
        samples.iter().all(|s| s.len() == d),
        "fit_pca: sample dim mismatch"
    );
    assert!(k <= d, "fit_pca: k must be <= d");
    let k = k.min(n); // can't fit more components than samples
    let mut rng = fastrand::Rng::with_seed(seed);

    // 1. Mean
    let mut mean = vec![0.0f32; d];
    for s in samples {
        for j in 0..d {
            mean[j] += s[j];
        }
    }
    for j in 0..d {
        mean[j] /= n as f32;
    }

    // 2. Centered sample matrix (n × d, row-major)
    let mut x = vec![0.0f32; n * d];
    for (i, s) in samples.iter().enumerate() {
        for j in 0..d {
            x[i * d + j] = s[j] - mean[j];
        }
    }

    // 3. Power iteration with explicit Gram-Schmidt deflation
    let mut basis = vec![0.0f32; k * d];
    let mut v = vec![0.0f32; d];
    let mut u = vec![0.0f32; n];
    let mut vn = vec![0.0f32; d];

    for c in 0..k {
        // Random init, normalize
        for j in 0..d {
            v[j] = rng.f32() - 0.5;
        }
        // Deflate init against existing components so we don't trivially recover them
        for prev in 0..c {
            let mut dot = 0.0f32;
            let row = &basis[prev * d..(prev + 1) * d];
            for j in 0..d {
                dot += row[j] * v[j];
            }
            for j in 0..d {
                v[j] -= dot * row[j];
            }
        }
        let norm = v.iter().map(|x| x * x).sum::<f32>().sqrt().max(1e-12);
        for j in 0..d {
            v[j] /= norm;
        }

        for _ in 0..num_iter {
            // u = X v (n-dim)
            for i in 0..n {
                let mut acc = 0.0f32;
                let row = &x[i * d..(i + 1) * d];
                for j in 0..d {
                    acc += row[j] * v[j];
                }
                u[i] = acc;
            }
            // vn = X^T u (d-dim)
            for j in 0..d {
                vn[j] = 0.0;
            }
            for i in 0..n {
                let ui = u[i];
                let row = &x[i * d..(i + 1) * d];
                for j in 0..d {
                    vn[j] += row[j] * ui;
                }
            }
            // Deflate against previous components (keeps us in the orthogonal complement)
            for prev in 0..c {
                let mut dot = 0.0f32;
                let row = &basis[prev * d..(prev + 1) * d];
                for j in 0..d {
                    dot += row[j] * vn[j];
                }
                for j in 0..d {
                    vn[j] -= dot * row[j];
                }
            }
            // Normalize -> v
            let norm = vn.iter().map(|x| x * x).sum::<f32>().sqrt().max(1e-12);
            for j in 0..d {
                v[j] = vn[j] / norm;
            }
        }
        // Store
        for j in 0..d {
            basis[c * d + j] = v[j];
        }
    }
    (mean, basis)
}

/// Project `x ∈ ℝ^d` to `x' ∈ ℝ^k` via `x' = O · x`, where `basis` is the
/// row-major `k × d` matrix from `random_orthogonal_basis`.
pub fn project_orthogonal(x: &[f32], basis: &[f32], k: usize, d: usize) -> Vec<f32> {
    debug_assert_eq!(x.len(), d);
    debug_assert_eq!(basis.len(), k * d);
    let mut out = vec![0.0f32; k];
    for i in 0..k {
        let mut acc = 0.0f32;
        let row = &basis[i * d..(i + 1) * d];
        for c in 0..d {
            acc += row[c] * x[c];
        }
        out[i] = acc;
    }
    out
}

/// Lift `x' ∈ ℝ^k` back to `x_recon ∈ ℝ^d` via `x_recon = O^T · x'`.
/// The result is the rank-k projection of the original onto row(O); not the
/// identity unless k == d. With orthonormal rows, `O^T · O · x` = projection
/// of x onto the row-space — the L2-best rank-k approximation of x in row(O).
pub fn lift_orthogonal(projected: &[f32], basis: &[f32], k: usize, d: usize) -> Vec<f32> {
    debug_assert_eq!(projected.len(), k);
    debug_assert_eq!(basis.len(), k * d);
    let mut out = vec![0.0f32; d];
    for i in 0..k {
        let coeff = projected[i];
        let row = &basis[i * d..(i + 1) * d];
        for c in 0..d {
            out[c] += coeff * row[c];
        }
    }
    out
}

/// Top-k singular values of a row-major `m × d` matrix via power iteration
/// with deflation. Picks the smaller side: builds `W W^T` (m × m) when
/// rows < cols, else `W^T W` (d × d). Eigenvalues of either give σ²; the
/// singular values are the same.
///
/// This is the "function PCA" companion to `fit_pca`: instead of finding
/// the basis activations live on, it finds the basis the operator's
/// behaviour lives on. If `σ_k+1 / σ_1 << 1`, the matrix is *behaviorally
/// rank-k* — you can replace `W` with `U_k Σ_k V_k^T` for a much smaller
/// asset and the function it implements is approximately preserved.
///
/// Cost: O(k * num_iter * s²) where `s = min(rows, cols)`. For Qwen2.5-0.5B's
/// `ffn.down` (896 × 4864): s = 896, M is 896 × 896 = ~3 MB. Sub-minute total.
pub fn top_k_singular_values(
    matrix: &[f32],
    rows: usize,
    cols: usize,
    k_top: usize,
    num_iter: usize,
    seed: u64,
) -> Vec<f32> {
    assert_eq!(
        matrix.len(),
        rows * cols,
        "top_k_singular_values: shape mismatch"
    );
    let k = k_top.min(rows).min(cols);
    // Pick the cheap side: W W^T (m × m) if rows ≤ cols, else W^T W (d × d).
    let use_wwt = rows <= cols;
    let s = if use_wwt { rows } else { cols };

    let mut m_mat = vec![0.0f32; s * s];
    if use_wwt {
        // M[i,j] = Σ_c W[i,c] * W[j,c]
        for i in 0..rows {
            let row_i = &matrix[i * cols..(i + 1) * cols];
            for j in i..rows {
                let row_j = &matrix[j * cols..(j + 1) * cols];
                let mut acc = 0.0f32;
                for c in 0..cols {
                    acc += row_i[c] * row_j[c];
                }
                m_mat[i * s + j] = acc;
            }
        }
    } else {
        // M[i,j] = Σ_r W[r,i] * W[r,j]  (the original W^T W path)
        for r in 0..rows {
            let row = &matrix[r * cols..(r + 1) * cols];
            for i in 0..s {
                let xi = row[i];
                if xi == 0.0 {
                    continue;
                }
                for j in i..s {
                    m_mat[i * s + j] += xi * row[j];
                }
            }
        }
    }
    // mirror upper triangle
    for i in 0..s {
        for j in (i + 1)..s {
            m_mat[j * s + i] = m_mat[i * s + j];
        }
    }
    let d = s;

    let mut rng = fastrand::Rng::with_seed(seed);
    let mut sigmas = Vec::with_capacity(k);
    let mut eigvecs = vec![0.0f32; k * d];
    let mut v = vec![0.0f32; d];
    let mut mv = vec![0.0f32; d];

    for c in 0..k {
        for j in 0..d {
            v[j] = rng.f32() - 0.5;
        }
        for prev in 0..c {
            let mut dot = 0.0f32;
            let row = &eigvecs[prev * d..(prev + 1) * d];
            for j in 0..d {
                dot += row[j] * v[j];
            }
            for j in 0..d {
                v[j] -= dot * row[j];
            }
        }
        let n = v.iter().map(|x| x * x).sum::<f32>().sqrt().max(1e-12);
        for j in 0..d {
            v[j] /= n;
        }

        for _ in 0..num_iter {
            // mv = M v
            for i in 0..d {
                let mut acc = 0.0f32;
                let row = &m_mat[i * d..(i + 1) * d];
                for j in 0..d {
                    acc += row[j] * v[j];
                }
                mv[i] = acc;
            }
            // deflate against previous eigvecs
            for prev in 0..c {
                let mut dot = 0.0f32;
                let row = &eigvecs[prev * d..(prev + 1) * d];
                for j in 0..d {
                    dot += row[j] * mv[j];
                }
                for j in 0..d {
                    mv[j] -= dot * row[j];
                }
            }
            let n = mv.iter().map(|x| x * x).sum::<f32>().sqrt().max(1e-12);
            for j in 0..d {
                v[j] = mv[j] / n;
            }
        }

        // σ² = v^T M v (Rayleigh quotient)
        let mut acc = 0.0f32;
        for i in 0..d {
            let row = &m_mat[i * d..(i + 1) * d];
            let mut s = 0.0f32;
            for j in 0..d {
                s += row[j] * v[j];
            }
            acc += v[i] * s;
        }
        let sigma = acc.max(0.0).sqrt();
        sigmas.push(sigma);
        for j in 0..d {
            eigvecs[c * d + j] = v[j];
        }
    }
    sigmas
}

/// Top-k SVD of a row-major `m × n` matrix. Returns `(a, b, sigmas)` where
/// `W ≈ a @ b` (`a` is `m × k`, `b` is `k × n`, both row-major) — singular
/// values are pre-folded into `a`. To use: y = a @ (b @ x) reduces an
/// O(m*n) matmul to O(k*(m+n)).
///
/// Implementation: power-iterate on the smaller of `W^T W` / `W W^T` to
/// get eigvecs (which are right or left singular vectors depending on
/// which side we picked), then derive the other factor by W * eigvec /
/// sigma.
pub fn top_k_svd(
    matrix: &[f32],
    rows: usize,
    cols: usize,
    k_top: usize,
    num_iter: usize,
    seed: u64,
) -> (Vec<f32>, Vec<f32>, Vec<f32>) {
    assert_eq!(matrix.len(), rows * cols, "top_k_svd: shape mismatch");
    let k = k_top.min(rows).min(cols);
    let use_wwt = rows <= cols;
    let s = if use_wwt { rows } else { cols };

    // Build M (s × s)
    let mut m_mat = vec![0.0f32; s * s];
    if use_wwt {
        for i in 0..rows {
            let row_i = &matrix[i * cols..(i + 1) * cols];
            for j in i..rows {
                let row_j = &matrix[j * cols..(j + 1) * cols];
                let mut acc = 0.0f32;
                for c in 0..cols {
                    acc += row_i[c] * row_j[c];
                }
                m_mat[i * s + j] = acc;
            }
        }
    } else {
        for r in 0..rows {
            let row = &matrix[r * cols..(r + 1) * cols];
            for i in 0..s {
                let xi = row[i];
                if xi == 0.0 {
                    continue;
                }
                for j in i..s {
                    m_mat[i * s + j] += xi * row[j];
                }
            }
        }
    }
    for i in 0..s {
        for j in (i + 1)..s {
            m_mat[j * s + i] = m_mat[i * s + j];
        }
    }
    let d = s;

    // Power iteration with deflation → top-k eigvecs (k × d row-major)
    let mut rng = fastrand::Rng::with_seed(seed);
    let mut eigvecs = vec![0.0f32; k * d];
    let mut sigmas = Vec::with_capacity(k);
    let mut v = vec![0.0f32; d];
    let mut mv = vec![0.0f32; d];

    for c in 0..k {
        for j in 0..d {
            v[j] = rng.f32() - 0.5;
        }
        for prev in 0..c {
            let mut dot = 0.0f32;
            let row = &eigvecs[prev * d..(prev + 1) * d];
            for j in 0..d {
                dot += row[j] * v[j];
            }
            for j in 0..d {
                v[j] -= dot * row[j];
            }
        }
        let n = v.iter().map(|x| x * x).sum::<f32>().sqrt().max(1e-12);
        for j in 0..d {
            v[j] /= n;
        }

        for _ in 0..num_iter {
            for i in 0..d {
                let mut acc = 0.0f32;
                let row = &m_mat[i * d..(i + 1) * d];
                for j in 0..d {
                    acc += row[j] * v[j];
                }
                mv[i] = acc;
            }
            for prev in 0..c {
                let mut dot = 0.0f32;
                let row = &eigvecs[prev * d..(prev + 1) * d];
                for j in 0..d {
                    dot += row[j] * mv[j];
                }
                for j in 0..d {
                    mv[j] -= dot * row[j];
                }
            }
            let n = mv.iter().map(|x| x * x).sum::<f32>().sqrt().max(1e-12);
            for j in 0..d {
                v[j] = mv[j] / n;
            }
        }
        let mut acc = 0.0f32;
        for i in 0..d {
            let row = &m_mat[i * d..(i + 1) * d];
            let mut sx = 0.0f32;
            for j in 0..d {
                sx += row[j] * v[j];
            }
            acc += v[i] * sx;
        }
        let sigma = acc.max(0.0).sqrt();
        sigmas.push(sigma);
        for j in 0..d {
            eigvecs[c * d + j] = v[j];
        }
    }

    // Build a (m × k) and b (k × n) such that W ≈ a @ b.
    // - use_wwt path: eigvecs are LEFT singular vectors U (k × m).
    //     a = U^T @ diag(sigmas)   (m × k, row-major)
    //     b = (1/sigma) * U @ W    (k × n) — exactly V^T @ diag(sigmas)
    //     Combined: a @ b = U @ diag(sigmas²/sigma) @ V^T = U Σ V^T = W
    //   So we want a[i,c] = U[c,i] and b[c,n] = sum_m U[c,m] * W[m,n]
    //   then a @ b yields each (m,n) entry as sum_c U[c,m] * (sum_i U[c,i] * W[i,n])
    //   = sum_c U[c,m] * (W^T U[c,:])[n] which is the U Σ V^T reconstruction.
    let mut a = vec![0.0f32; rows * k];
    let mut b = vec![0.0f32; k * cols];
    if use_wwt {
        // a = U^T (m × k): a[m,c] = eigvecs[c,m]
        for c in 0..k {
            for m in 0..rows {
                a[m * k + c] = eigvecs[c * d + m];
            }
        }
        // b = U @ W (k × n): b[c,n] = sum_m eigvecs[c,m] * W[m,n]
        for c in 0..k {
            let u_c = &eigvecs[c * d..(c + 1) * d];
            for n in 0..cols {
                let mut acc = 0.0f32;
                for m in 0..rows {
                    acc += u_c[m] * matrix[m * cols + n];
                }
                b[c * cols + n] = acc;
            }
        }
    } else {
        // eigvecs are RIGHT singular vectors V (k × n).
        // We want a = W @ V (m × k) and b = V^T (k × n) — but with sigmas
        // folded somewhere. Easiest: a[m,c] = sum_n W[m,n] * V[c,n], b = V.
        for c in 0..k {
            let v_c = &eigvecs[c * d..(c + 1) * d];
            for m in 0..rows {
                let mut acc = 0.0f32;
                let row = &matrix[m * cols..(m + 1) * cols];
                for n in 0..cols {
                    acc += row[n] * v_c[n];
                }
                a[m * k + c] = acc;
            }
            for n in 0..cols {
                b[c * cols + n] = v_c[n];
            }
        }
    }
    (a, b, sigmas)
}

/// On-disk format for a per-layer fitted PCA basis. Sidecar to a `.knot`.
///
/// Magic     : "PCAB"           (4 bytes)
/// Version   : u32 LE           (currently 1)
/// num_layers: u32 LE
/// hidden_dim: u32 LE
/// (per layer, in layer-index order):
///   layer_idx : u32 LE
///   k         : u32 LE         (0 means "no basis fitted for this layer")
///   mean      : k > 0 ? d × f32 LE : empty
///   basis     : k > 0 ? k*d × f32 LE : empty
///
/// `bases[i]` is `(layer_idx, k, mean, basis)`. Layers without a fitted
/// basis can be omitted (use k=0 entries) or simply skipped — the loader
/// handles both.
pub fn write_pca_bases(
    path: &str,
    hidden_dim: usize,
    num_layers: usize,
    bases: &[(usize, usize, Vec<f32>, Vec<f32>)],
) -> std::io::Result<()> {
    use std::fs::File;
    use std::io::Write;
    let mut f = File::create(path)?;
    f.write_all(b"PCAB")?;
    f.write_all(&1u32.to_le_bytes())?;
    f.write_all(&(num_layers as u32).to_le_bytes())?;
    f.write_all(&(hidden_dim as u32).to_le_bytes())?;
    for (l, k, mean, basis) in bases {
        f.write_all(&(*l as u32).to_le_bytes())?;
        f.write_all(&(*k as u32).to_le_bytes())?;
        if *k > 0 {
            for v in mean {
                f.write_all(&v.to_le_bytes())?;
            }
            for v in basis {
                f.write_all(&v.to_le_bytes())?;
            }
        }
    }
    Ok(())
}

/// On-disk format for per-layer FFN-down low-rank factorizations.
/// Mirror of write_pca_bases for the operator side. Sidecar to a `.knot`.
///
/// Magic     : "LRFD" (Low-Rank FFN Down) (4 bytes)
/// Version   : u32 LE  (currently 1)
/// num_layers: u32 LE
/// hidden_dim: u32 LE  (m, output rows of W)
/// inter_size: u32 LE  (n, input cols of W)
/// (per layer, in layer-index order):
///   layer_idx : u32 LE
///   k         : u32 LE         (0 means "no factor for this layer")
///   a         : k > 0 ? m*k × f32 LE : empty   (row-major m × k)
///   b         : k > 0 ? k*n × f32 LE : empty   (row-major k × n)
pub fn write_ffn_down_lowrank(
    path: &str,
    hidden_dim: usize,
    intermediate_size: usize,
    num_layers: usize,
    factors: &[(usize, usize, Vec<f32>, Vec<f32>)],
) -> std::io::Result<()> {
    use std::fs::File;
    use std::io::Write;
    let mut f = File::create(path)?;
    f.write_all(b"LRFD")?;
    f.write_all(&1u32.to_le_bytes())?;
    f.write_all(&(num_layers as u32).to_le_bytes())?;
    f.write_all(&(hidden_dim as u32).to_le_bytes())?;
    f.write_all(&(intermediate_size as u32).to_le_bytes())?;
    for (l, k, a, b) in factors {
        f.write_all(&(*l as u32).to_le_bytes())?;
        f.write_all(&(*k as u32).to_le_bytes())?;
        if *k > 0 {
            for v in a {
                f.write_all(&v.to_le_bytes())?;
            }
            for v in b {
                f.write_all(&v.to_le_bytes())?;
            }
        }
    }
    Ok(())
}

/// On-disk format for per-layer attention K and V projection low-rank
/// factorizations. Mirror of LRFD but holds two factor sets per layer
/// (one for W_k, one for W_v), with `kv_dim` (= num_kv_heads × head_dim)
/// as the output dim instead of `hidden_dim`.
///
/// Magic     : "LRKV" (4 bytes)
/// Version   : u32 LE  (currently 1)
/// num_layers: u32 LE
/// hidden_dim: u32 LE  (n, input cols of W_k and W_v)
/// kv_dim    : u32 LE  (m, output rows of W_k and W_v)
/// (per layer, in layer-index order):
///   layer_idx : u32 LE
///   tag       : u32 LE  (0 = K factor, 1 = V factor; sentinel records
///                        for K and V are interleaved per layer)
///   k         : u32 LE  (rank; 0 means "no factor for this (layer, kind)")
///   a         : k > 0 ? m*k × f32 LE : empty   (row-major m × k)
///   b         : k > 0 ? k*n × f32 LE : empty   (row-major k × n)
pub fn write_attn_kv_lowrank(
    path: &str,
    hidden_dim: usize,
    kv_dim: usize,
    num_layers: usize,
    factors: &[(usize, u32, usize, Vec<f32>, Vec<f32>)],
) -> std::io::Result<()> {
    use std::fs::File;
    use std::io::Write;
    let mut f = File::create(path)?;
    f.write_all(b"LRKV")?;
    f.write_all(&1u32.to_le_bytes())?;
    f.write_all(&(num_layers as u32).to_le_bytes())?;
    f.write_all(&(hidden_dim as u32).to_le_bytes())?;
    f.write_all(&(kv_dim as u32).to_le_bytes())?;
    for (l, tag, k, a, b) in factors {
        f.write_all(&(*l as u32).to_le_bytes())?;
        f.write_all(&(*tag).to_le_bytes())?;
        f.write_all(&(*k as u32).to_le_bytes())?;
        if *k > 0 {
            for v in a {
                f.write_all(&v.to_le_bytes())?;
            }
            for v in b {
                f.write_all(&v.to_le_bytes())?;
            }
        }
    }
    Ok(())
}

/// Read a `.lrkv` sidecar back into `(hidden_dim, kv_dim, num_layers, factors)`.
/// `factors[i] = (layer_idx, tag, k, a, b)` where tag 0 = K, tag 1 = V.
pub fn read_attn_kv_lowrank(
    path: &str,
) -> std::io::Result<(
    usize,
    usize,
    usize,
    Vec<(usize, u32, usize, Vec<f32>, Vec<f32>)>,
)> {
    use std::fs::File;
    use std::io::Read;
    let mut f = File::open(path)?;
    let mut buf4 = [0u8; 4];
    f.read_exact(&mut buf4)?;
    if &buf4 != b"LRKV" {
        return Err(std::io::Error::new(
            std::io::ErrorKind::InvalidData,
            format!("bad lrkv magic: {:?}", buf4),
        ));
    }
    f.read_exact(&mut buf4)?;
    let version = u32::from_le_bytes(buf4);
    if version != 1 {
        return Err(std::io::Error::new(
            std::io::ErrorKind::InvalidData,
            format!("unsupported lrkv version: {}", version),
        ));
    }
    f.read_exact(&mut buf4)?;
    let num_layers = u32::from_le_bytes(buf4) as usize;
    f.read_exact(&mut buf4)?;
    let hidden_dim = u32::from_le_bytes(buf4) as usize;
    f.read_exact(&mut buf4)?;
    let kv_dim = u32::from_le_bytes(buf4) as usize;
    let mut factors = Vec::new();
    let mut tmp = Vec::new();
    loop {
        let mut hdr = [0u8; 12];
        match f.read_exact(&mut hdr) {
            Ok(()) => {}
            Err(e) if e.kind() == std::io::ErrorKind::UnexpectedEof => break,
            Err(e) => return Err(e),
        }
        let l = u32::from_le_bytes(hdr[0..4].try_into().unwrap()) as usize;
        let tag = u32::from_le_bytes(hdr[4..8].try_into().unwrap());
        let k = u32::from_le_bytes(hdr[8..12].try_into().unwrap()) as usize;
        if k == 0 {
            factors.push((l, tag, 0, Vec::new(), Vec::new()));
            continue;
        }
        let n_a = kv_dim * k;
        let n_b = k * hidden_dim;
        tmp.resize((n_a + n_b) * 4, 0u8);
        f.read_exact(&mut tmp)?;
        let a: Vec<f32> = (0..n_a)
            .map(|i| f32::from_le_bytes(tmp[i * 4..(i + 1) * 4].try_into().unwrap()))
            .collect();
        let b: Vec<f32> = (0..n_b)
            .map(|i| {
                let off = (n_a + i) * 4;
                f32::from_le_bytes(tmp[off..off + 4].try_into().unwrap())
            })
            .collect();
        factors.push((l, tag, k, a, b));
    }
    Ok((hidden_dim, kv_dim, num_layers, factors))
}

